    "finance.confirm_pay_msg_immutable": "Questa operazione registra il pagamento come una scrittura contabile immutabile e chiude la fattura. Non può essere annullata.",
    "finance.invoice_sent_for_approval": "Fattura inviata per approvazione",
    "finance.send_for_approval": "Invia per approvazione",
    "finance.send_for_approval_failed": "Invio della fattura per approvazione non riuscito",
    "finance.send_for_approval_hint": "Sposta questa fattura in bozza su in attesa, così un responsabile può approvarla.",
    "finance.status_current": "attuale",
    "finance.status_edit_hint": "Sposta la fattura tra bozza, in attesa e annullata. L'approvazione di una fattura e il segnarla come pagata si effettuano dai pulsanti Approva e Segna pagata sulla riga della fattura.",
    "finance.status_label": "Stato",
    "geo_hub.empty.no_anchor_description_v2": "Ancora automaticamente dall'indirizzo impostato nelle impostazioni del progetto, oppure scegli una coordinata manualmente. Puoi regolare con precisione trascinando una volta posizionato il segnaposto.",
    "geo_hub.empty.no_anchor_description_v3": "Ancora automaticamente dall'indirizzo impostato nelle impostazioni del progetto, oppure posiziona un segnaposto direttamente sulla mappa. Puoi regolare con precisione trascinando una volta posizionato il segnaposto.",
    "geo_hub.empty.place_manually_cta": "Posiziona un segnaposto sulla mappa",
    "geo_hub.place_anchor.instruction": "Fai clic sulla mappa per posizionare questo progetto",
    "geo_hub.place_anchor.locating": "Localizzazione del progetto dal suo indirizzo...",
    "projects.no_archived_hint": "Nessun progetto archiviato. Torna ai progetti attivi qui sotto.",
    "projects.show_active": "Mostra progetti attivi",
    "sidebar.group.procurement_desc": "Tre modi per acquistare. RFQ per preventivi rapidi, Gestione Offerte per gare competitive formali, Gare d'Appalto quando si prezza a partire da un computo metrico.",
    "sidebar.group.change": "Modifiche e Registrazioni",
    "sidebar.help.procurement": "Dai preventivi rapidi dei fornitori (RFQ) fino agli ordini d'acquisto.",
    "sidebar.help.bid_management": "Gara formale con inviti agli offerenti, una bacheca delle domande e il livellamento delle offerte.",
