    "journey.phase.setup.name": "Imposta il progetto",
    "journey.phase.setup.desc": "Crea il progetto, definisci gli standard e la valuta di base, invita il team.",
    "journey.phase.capture.name": "Acquisisci il progetto",
    "journey.phase.capture.desc": "Riunisci disegni, modelli BIM e scansioni della realta in un unico posto e coordinali.",
    "journey.phase.quantify.name": "Quantifica",
    "journey.phase.quantify.desc": "Raccogli le quantita, poi filtrale e raggruppale nella struttura richiesta dalla tua stima.",
